### Swift Protocol Inheritance

Protocols can inherit from other protocols, allowing you to build hierarchies of requirements. A protocol can inherit from multiple other protocols.

**Protocol Inheritance Syntax:**

```swift
protocol InheritingProtocol: BaseProtocol1, BaseProtocol2 {
    // Additional requirements
}
```

**Basic Inheritance:**

```swift
protocol Named {
    var name: String { get }
}

protocol Aged {
    var age: Int { get }
}

// Protocol inheriting from multiple protocols
protocol Person: Named, Aged {
    var email: String { get }
    func introduce() -> String
}

struct Employee: Person {
    let name: String
    let age: Int
    let email: String

    func introduce() -> String {
        return "Hi, I'm \(name), \(age) years old. Email: \(email)"
    }
}
```

**Protocol Hierarchy Example:**

```swift
protocol Animal {
    var species: String { get }
    func makeSound() -> String
}

protocol Mammal: Animal {
    var hasFur: Bool { get }
}

protocol Pet: Mammal {
    var name: String { get }
    func play() -> String
}

struct Dog: Pet {
    let species = "Canine"
    let hasFur = true
    let name: String

    func makeSound() -> String { "Woof!" }
    func play() -> String { "\(name) plays fetch" }
}
```

**Class-Specific Protocols:**

| Keyword | Conforming Types |
|---------|-----------------|
| `protocol` | Classes, structs, enums |
| `protocol: AnyObject` | Classes only (reference types) |

```swift
protocol NetworkDelegate: AnyObject {
    func didReceiveData(_ data: Data)
    func didFailWithError(_ error: Error)
}

// Only classes can conform
class ViewController: NetworkDelegate {
    func didReceiveData(_ data: Data) { }
    func didFailWithError(_ error: Error) { }
}

// struct ViewModel: NetworkDelegate { }  // Error!
```

**Protocol Composition:**

```swift
func processItem(_ item: Named & Aged) {
    print("\(item.name) is \(item.age) years old")
}

// The parameter must conform to BOTH Named and Aged
```

> **Key Point:** Protocol inheritance allows you to compose requirements incrementally. A type that conforms to an inheriting protocol must satisfy all requirements from the entire hierarchy.

Use `AnyObject` constraint when you need weak references or reference semantics for protocol conformance.

codeExample:
import Foundation

protocol Drawable {
    func draw() -> String
}

protocol Fillable {
    var fillColor: String { get set }
    func fill() -> String
}

protocol ColoredShape: Drawable, Fillable {
    var borderColor: String { get set }
    func border() -> String
}

struct Circle: ColoredShape {
    var fillColor: String = "red"
    var borderColor: String = "black"

    func draw() -> String {
        "Drawing circle"
    }

    func fill() -> String {
        "Filling with \(fillColor)"
    }

    func border() -> String {
        "Adding \(borderColor) border"
    }
}

let circle = Circle()
print(circle.draw())
print(circle.fill())
print(circle.border())

// Protocol composition
protocol Printable {
    func print() -> String
}

struct Report: Printable & Named {
    let name: String
    let content: String

    func print() -> String {
        "Report: \(name)\n\(content)"
    }
}

let report = Report(name: "Q1 Results", content: "Revenue up 20%")
print(report.print())
